"use client";
// Mirrors React-template InteractiveBanners01.jsx–InteractiveBanners15.jsx

import { useState, type ReactNode } from "react";

export interface BannerItem {
  img: string;
  subtitle?: string;
  title: string;
  btnTitle?: string;
  btnLink?: string;
  text?: string;
  icon?: ReactNode;
  badge?: string;
  tag?: string;
}

type ThemeVal =
  | "interactive-banners-01" | "interactive-banners-02" | "interactive-banners-03"
  | "interactive-banners-04" | "interactive-banners-05" | "interactive-banners-06"
  | "interactive-banners-07" | "interactive-banners-08" | "interactive-banners-09"
  | "interactive-banners-10" | "interactive-banners-11" | "interactive-banners-12"
  | "interactive-banners-13" | "interactive-banners-14" | "interactive-banners-15";

interface Props {
  theme?: ThemeVal;
  data: BannerItem[];
  grid?: string;
}

const CARD_GRIDS: Partial<Record<ThemeVal, string>> = {
  "interactive-banners-08": "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",
  "interactive-banners-09": "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",
  "interactive-banners-11": "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",
  "interactive-banners-14": "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3",
};

export default function InteractiveBanners({ theme = "interactive-banners-01", data, grid }: Props) {
  if (theme === "interactive-banners-02") return <CarouselBanners data={data} />;

  const defaultGrid = CARD_GRIDS[theme] ?? "grid-cols-2 lg:grid-cols-4";
  const cls = `grid ${grid ?? defaultGrid} gap-4`;

  return (
    <div className={cls}>
      {data.map((item, i) => {
        switch (theme) {
          case "interactive-banners-03": return <IB03 key={i} item={item} />;
          case "interactive-banners-04": return <IB04 key={i} item={item} />;
          case "interactive-banners-05": return <IB05 key={i} item={item} />;
          case "interactive-banners-06": return <IB06 key={i} item={item} />;
          case "interactive-banners-07": return <IB07 key={i} item={item} />;
          case "interactive-banners-08": return <IB08 key={i} item={item} />;
          case "interactive-banners-09": return <IB09 key={i} item={item} />;
          case "interactive-banners-10": return <IB10 key={i} item={item} />;
          case "interactive-banners-11": return <IB11 key={i} item={item} />;
          case "interactive-banners-12": return <IB12 key={i} item={item} />;
          case "interactive-banners-13": return <IB13 key={i} item={item} />;
          case "interactive-banners-14": return <IB14 key={i} item={item} />;
          case "interactive-banners-15": return <IB15 key={i} item={item} />;
          default: return (
            <div key={i} className="ib-01">
              <img src={item.img} alt={item.title} />
              <div className="ib-overlay" />
              <div className="ib-content">
                {item.subtitle && <div className="ib-sub">{item.subtitle}</div>}
                <h4>{item.title}</h4>
                {item.btnTitle && <a href={item.btnLink || "#"} className="ib-link">{item.btnTitle} →</a>}
              </div>
            </div>
          );
        }
      })}
    </div>
  );
}

function IB03({ item }: { item: BannerItem }) {
  return (
    <div className="ib-03">
      <img src={item.img} alt={item.title} />
      <div className="ib-content">
        {item.subtitle && <div className="ib-category">{item.subtitle}</div>}
        <h5 className="ib-title">{item.title}</h5>
      </div>
    </div>
  );
}

function IB04({ item }: { item: BannerItem }) {
  return (
    <div className="ib-04">
      <img src={item.img} alt={item.title} />
      <div className="ib-overlay">
        {item.icon && <div className="ib-icon">{item.icon}</div>}
        <div className="ib-title">{item.title}</div>
        {item.text && <div className="ib-text">{item.text}</div>}
      </div>
    </div>
  );
}

function IB05({ item }: { item: BannerItem }) {
  return (
    <div className="ib-05">
      <img src={item.img} alt={item.title} />
      <div className="ib-panel">
        <div className="ib-title">{item.title}</div>
        {item.text && <div className="ib-text">{item.text}</div>}
      </div>
    </div>
  );
}

function IB06({ item }: { item: BannerItem }) {
  return (
    <div className="ib-06">
      <img src={item.img} alt={item.title} />
      {item.badge && <div className="ib-badge">{item.badge}</div>}
      <div className="ib-title">{item.title}</div>
    </div>
  );
}

function IB07({ item }: { item: BannerItem }) {
  return (
    <div className="ib-07">
      <img src={item.img} alt={item.title} />
      <div className="ib-content">
        <div className="ib-title">{item.title}</div>
        {item.btnLink && <a href={item.btnLink} className="ib-link">{item.btnTitle || "View"}</a>}
      </div>
    </div>
  );
}

function IB08({ item }: { item: BannerItem }) {
  return (
    <div className="ib-08">
      <div className="ib-icon">{item.icon || "★"}</div>
      <div>
        <h5>{item.title}</h5>
        <p>{item.text || item.subtitle || ""}</p>
      </div>
    </div>
  );
}

function IB09({ item }: { item: BannerItem }) {
  return (
    <div className="ib-09">
      <div className="ib-icon">{item.icon || "★"}</div>
      <h5>{item.title}</h5>
      <p>{item.text || item.subtitle || ""}</p>
    </div>
  );
}

function IB10({ item }: { item: BannerItem }) {
  return (
    <div className="ib-10">
      <img src={item.img} alt={item.title} />
      <div className="ib-side" />
      <div className="ib-content">
        <div className="ib-title">{item.title}</div>
        {item.subtitle && <div className="ib-sub">{item.subtitle}</div>}
      </div>
    </div>
  );
}

function IB11({ item }: { item: BannerItem }) {
  return (
    <div className="ib-11">
      <img src={item.img} alt={item.title} />
      <div className="ib-body">
        <h5>{item.title}</h5>
        <p>{item.text || ""}</p>
        {item.btnLink && <a href={item.btnLink} className="ib-link">{item.btnTitle || "Read more"} →</a>}
      </div>
    </div>
  );
}

function IB12({ item }: { item: BannerItem }) {
  return (
    <div className="ib-12">
      <img src={item.img} alt={item.title} />
      <div className="ib-caption">
        {item.icon && <div className="ib-icon">{item.icon}</div>}
        <div className="ib-title">{item.title}</div>
      </div>
    </div>
  );
}

function IB13({ item }: { item: BannerItem }) {
  return (
    <div className="ib-13">
      <img src={item.img} alt={item.title} />
      {item.tag && <div className="ib-tag">{item.tag}</div>}
      <div className="ib-footer">
        <div className="ib-title">{item.title}</div>
        {item.btnLink && <a href={item.btnLink} className="ib-btn">{item.btnTitle || "View"}</a>}
      </div>
    </div>
  );
}

function IB14({ item }: { item: BannerItem }) {
  return (
    <div className="ib-14">
      <img src={item.img} alt={item.title} />
      <div className="ib-body">
        <h6>{item.title}</h6>
        <p>{item.text || item.subtitle || ""}</p>
      </div>
    </div>
  );
}

function IB15({ item }: { item: BannerItem }) {
  return (
    <div className="ib-15">
      <img src={item.img} alt={item.title} />
      <div className="ib-content">
        {item.icon && <div className="ib-icon">{item.icon}</div>}
        <div className="ib-title">{item.title}</div>
        {item.text && <div className="ib-text">{item.text}</div>}
      </div>
    </div>
  );
}

function CarouselBanners({ data }: { data: BannerItem[] }) {
  const [idx, setIdx] = useState(0);
  const visible = 3;
  const prev = () => setIdx(Math.max(0, idx - 1));
  const next = () => setIdx(Math.min(data.length - visible, idx + 1));

  return (
    <div className="relative">
      <div className="grid gap-4" style={{ gridTemplateColumns: `repeat(${visible}, 1fr)` }}>
        {data.slice(idx, idx + visible).map((item, i) => (
          <div key={i} className="ib-01" style={{ minHeight: 340 }}>
            <img src={item.img} alt={item.title} />
            <div className="ib-overlay" />
            <div className="ib-content">
              {item.subtitle && <div className="ib-sub">{item.subtitle}</div>}
              <h4>{item.title}</h4>
              {item.btnTitle && <a href={item.btnLink || "#"} className="ib-link">{item.btnTitle} →</a>}
            </div>
          </div>
        ))}
      </div>
      {idx > 0 && (
        <button onClick={prev} className="absolute left-[-20px] top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white shadow-md flex items-center justify-center hover:bg-[--primary] hover:text-white transition-all">←</button>
      )}
      {idx + visible < data.length && (
        <button onClick={next} className="absolute right-[-20px] top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white shadow-md flex items-center justify-center hover:bg-[--primary] hover:text-white transition-all">→</button>
      )}
    </div>
  );
}
